const year = $json.year || new Date().getFullYear();
const month = $json.month || new Date().getMonth() + 1;
const queryType = $json.queryType || 'details';
const category = $json.category || null;

const sheetsMap = JSON.parse($json.sheetsMapJson || '{}');
const key = `${year}-${String(month).padStart(2, '0')}`;
const spreadsheetId = sheetsMap[key];

if (!spreadsheetId) {
  throw new Error(`找不到 ${year} 年 ${month} 月的帳本（請在 .env 的 EXPENSE_SHEETS_MAP 中新增 "${key}" 的設定）`);
}

return {
  spreadsheetId: spreadsheetId,
  documentName: `${year} ${month}月 開支清單`,
  category: category,
  year: year,
  month: month,
  queryType: queryType
};

parameters.jsCode:
const items = $input.all();
const category = $('Parse and Route').first().json.category;
const year = $('Parse and Route').first().json.year;
const month = $('Parse and Route').first().json.month;

let result = items.map(item => ({
  日期: item.json.日期 || item.json['Date'],
  項目: item.json.項目 || item.json['Item'],
  分類: item.json.分類 || item.json['Category'],
  金額: item.json.金額 || item.json['Amount'],
  幣值: item.json.幣值 || item.json['Currency'] || 'TWD',
  備註: item.json.備註 || item.json['Note'] || ''
}));

if (category) {
  result = result.filter(item => item.分類 && item.分類.includes(category));
}

const totalByCategory = {};
const totalByCurrency = {};

result.forEach(item => {
  const cat = item.分類 || '未分類';
  const currency = item.幣值 || 'TWD';
  const amount = parseFloat(item.金額) || 0;

  if (!totalByCategory[cat]) totalByCategory[cat] = {};
  if (!totalByCategory[cat][currency]) totalByCategory[cat][currency] = 0;
  totalByCategory[cat][currency] += amount;

  if (!totalByCurrency[currency]) totalByCurrency[currency] = 0;
  totalByCurrency[currency] += amount;
});

return [{
  json: {
    year,
    month,
    queryType: 'details',
    category,
    recordCount: result.length,
    records: result,
    totalByCategory,
    totalByCurrency
  }
}];

const items = $input.all();
const category = $('Parse and Route').first().json.category;
const year = $('Parse and Route').first().json.year;
const month = $('Parse and Route').first().json.month;

// Skip title row ("每月開支總結") and Subtotal row; use 幣別 column as category label
let result = items
  .map(item => item.json)
  .filter(row => {
    const label = row['幣別'] || '';
    return label && label !== '每月開支總結' && label !== 'Subtotal';
  })
  .map(row => ({
    分類: row['幣別'],
    JPY: parseFloat(row['JPY']) || 0,
    TWD: parseFloat(row['TWD']) || 0,
    USD: parseFloat(row['USD']) || 0
  }));

if (category) {
  result = result.filter(item => item.分類 && item.分類.includes(category));
}

return [{
  json: {
    year,
    month,
    queryType: 'summary',
    category,
    summary: result
  }
}];
